mapper.select:
SELECT o.id, o.order_no AS orderNo, o.patient_id AS patientId, p.name AS patientName, o.visit_id AS visitId, o.total_amount AS totalAmount, o.paid_amount AS paidAmount, o.pay_type AS payType, o.pay_status AS payStatus, o.pay_time AS payTime, o.create_time AS createTime FROM charge_order o LEFT JOIN patient p ON p.id = o.patient_id
AND o.pay_status = #{payStatus} AND o.patient_id = #{patientId}
ORDER BY o.create_time DESC

mapper.update:
UPDATE charge_order
SET paid_amount = #{paidAmount}, pay_type = #{payType}, pay_status = #{payStatus},
    cashier_id = #{cashierId}, pay_time = #{payTime}
WHERE id = #{id}
